import Layout from "./components/Layout/Layout";
import Menu from "./components/Menu/Menu";
import Menus from "./components/Menus/Menus";
import breadcrumb_img from "./images/breadbg1.jpg"
import "./global.css"
function App() {
  return (
    <Layout>
        <main>
            <div class="main-part">
              <section class="breadcrumb-part" data-stellar-offset-parent="true" data-stellar-background-ratio="0.5" style={{backgroundImage:`url(${breadcrumb_img})`}}>
                    <div class="container">
                        <div class="breadcrumb-inner">
                            <h2>SHOP</h2>
                            <a href="#">Home</a>
                            <span>Shop</span>
                        </div>
                    </div>
                </section>
                {/* <Menus/> */}
                <Menu/>


            </div>
        </main>
        {/* <Menus/> */}

    </Layout>
  );
}

export default App;
